<?php
if (session_status() === PHP_SESSION_NONE) session_start();
if (empty($_SESSION['is_logged_in'])) { header('Location: ../connexion.php'); exit; }
if (($_SESSION['user_type'] ?? '') !== 'acheteur') { header('Location: dashboard.php'); exit; }
require_once __DIR__ . '/../models/select/CommandeSelect.php';
$user_id = (int) $_SESSION['user_id']; $user_type = 'acheteur';
$user_nom = $_SESSION['user_nom'] ?? ''; $user_prenom = $_SESSION['user_prenom'] ?? ''; $user_email = $_SESSION['user_email'] ?? '';
$commandes = CommandeSelect::getByAcheteur($user_id);
$stats = ['total'=>count($commandes),'attente'=>0,'livraison'=>0,'livree'=>0];
foreach($commandes as $c){if($c->statut_commande==='en_attente')$stats['attente']++;elseif($c->statut_commande==='en_livraison')$stats['livraison']++;elseif($c->statut_commande==='livree')$stats['livree']++;}
?>
