ground:#dbeafe;color:#1d4ed8}.livree{background:#dcfce7;color:#166534}.annulee{background:#fee2e2;color:#991b1b}.detail{background:var(--soft);padding:13px;border-radius:9px}.products{margin-top:10px;padding-top:10px;border-top:1px solid var(--border)}@media(max-width:850px){.sidebar{position:static;width:100%}.layout{display:block}.main{margin:0;width:100%;padding:16px}.stats,.grid{grid-template-columns:1fr 1fr}}@media(max-width:520px){.stats,.grid{grid-template-columns:1fr}.order-head{display:block}}
