<article class="order"><div class="order-head"><div><strong>#<?=htmlspecialchars($c->numero_commande)?></strong><div class="muted small"><?=date('d/m/Y à H:i',strtotime($c->date_commande))?></div></div><span class="badge-status <?=htmlspecialchars($c->statut_commande)?>"><?=$labels[$c->statut_commande]??$c->statut_commande?></span></div><div class="grid"><div><div class="label">Montant</div><strong><?=number_format((float)$c->montant_total,0,',',' ')?> FC</strong></div><div><div class="label">Articles</div><strong><?=(int)$c->nb_produits?></strong></div><div><div class="label">Paiement</div><strong><?=htmlspecialchars($c->mode_paiement?:'Non renseigné')?></strong></div><div><div class="label">Suivi</div><strong><?=htmlspecialchars($c->code_suivi?:'Pas encore assigné')?></strong></div></div><div class="detail"><div class="label">Adresse de livraison</div><?=htmlspecialchars($c->adresse_livraison?:'Non renseignée')?><?php if($c->instructions_livraison):?><div class="muted small"><?=htmlspecialchars($c->instructions_livraison)?></div><?php endif;?><div class="products"><?php foreach($lignes as $ligne):?><div class="d-flex justify-content-between"><span><?=htmlspecialchars($ligne->produit_nom)?></span><strong><?=htmlspecialchars($ligne->quantite.' '.$ligne->unite_mesure)?></strong></div><?php endforeach;?></div></div></article><?php endforeach;?></section></main></div>
<script>function icon(){document.getElementById('themeIcon').className=document.documentElement.classList.contains('dark')?'bi bi-sun':'bi bi-moon-stars'}function toggleTheme(){document.documentElement.classList.toggle('dark');localStorage.setItem('theme',document.documentElement.classList.contains('dark')?'dark':'light');icon()}if(localStorage.getItem('theme')==='dark'||(!localStorage.getItem('theme')&&matchMedia('(prefers-color-scheme:dark)').matches))document.documentElement.classList.add('dark');icon()</script></body></html>
